const allItems = $input.all();
const upData = allItems[0]?.json;
const memData = allItems[1]?.json;

const services = [];
if (upData?.data?.result) {
  for (const r of upData.data.result) {
    const name = r.metric?.job || r.metric?.instance || 'unknown';
    const status = r.value?.[1] === '1' ? 'up' : 'down';
    services.push(`${status === 'up' ? '✓' : '✗'} ${name}: ${status}`);
  }
}

let memGB = null;
if (memData?.data?.result?.[0]?.value?.[1]) {
  const bytes = parseFloat(memData.data.result[0].value[1]);
  memGB = (bytes / 1024 / 1024 / 1024).toFixed(2);
}

const timestamp = new Date().toISOString();
const servicesText = services.length > 0 ? services.join('\n') : 'no metrics available';
const memText = memGB ? `Memory available: ${memGB} GB` : 'Memory: unavailable';

const summary = `Hourly metrics snapshot (${new Date().toLocaleTimeString()}):\n${memText}\nServices:\n${servicesText}`;

return [{
  json: {
    summary,
    memory_gb_available: memGB,
    services_up: services.filter(s => s.includes('✓')).length,
    services_down: services.filter(s => s.includes('✗')).length,
    timestamp
  }
}];
